import React, { useEffect, useState } from "react";
import axios from "axios";
import Swal from "sweetalert2";
import { FaEdit, FaTrash } from "react-icons/fa";
import "./dashboardhome.css";

const DashboardHome = () => {
  const [users, setUsers] = useState([]);
  const [editUser, setEditUser] = useState(null);
  const [formData, setFormData] = useState({
    name: "",
    email: "",
    role: "client",
    image: ""
  });
  const [showModal, setShowModal] = useState(false);

  // Charger la liste des utilisateurs
  useEffect(() => {
    fetchUsers();
  }, []);

  const fetchUsers = async () => {
    try {
      const response = await axios.get("http://localhost:5001/users");
      setUsers(response.data.users);  // Assuming the response contains the users in `data.users`
    } catch (error) {
      console.error("Error fetching users:", error);
    }
  };

  // Gérer la modification d'un utilisateur
  const handleEdit = (user) => {
    setEditUser(user);
    setFormData(user);
    setShowModal(true);
  };

  // Gérer les changements dans le formulaire
  const handleChange = (e) => {
    const { name, value } = e.target;
    setFormData({ ...formData, [name]: value });
  };

  // Gérer l'upload de l'image
  const handleImageChange = (e) => {
    const file = e.target.files[0];
    if (file) {
      const reader = new FileReader();
      reader.onloadend = () => {
        setFormData({ ...formData, image: reader.result });
      };
      reader.readAsDataURL(file);
    }
  };

  // Mettre à jour l'utilisateur
  const handleUpdate = async () => {
    try {
      await axios.put(`http://localhost:5001/users/${editUser._id}`, formData);
      fetchUsers();
      setShowModal(false);
      Swal.fire("Updated!", "User updated successfully", "success");
    } catch (error) {
      console.error("Error updating user:", error);
      Swal.fire("Error!", "Failed to update user", "error");
    }
  };

  // Supprimer un utilisateur
  const deleteUser = async (id) => {
    Swal.fire({
      title: "Are you sure?",
      text: "You won't be able to revert this!",
      icon: "warning",
      showCancelButton: true,
      confirmButtonColor: "#d33",
      cancelButtonColor: "#3085d6",
      confirmButtonText: "Yes, delete it!"
    }).then(async (result) => {
      if (result.isConfirmed) {
        try {
          await axios.delete(`http://localhost:5001/users/${id}`);
          fetchUsers();
          Swal.fire("Deleted!", "User has been deleted.", "success");
        } catch (error) {
          console.error("Error deleting user:", error);
          Swal.fire("Error!", "Failed to delete user", "error");
        }
      }
    });
  };

  return (
    <div className="dashboard-container">
      <h2>Users List</h2>
      <table>
        <thead>
          <tr>
            <th>Image</th>
            <th>Name</th>
            <th>Role</th>
            <th>Email</th>
            <th>Actions</th>
          </tr>
        </thead>
        <tbody>
          {users.map((user) => (
            <tr key={user._id}>
              <td>
                {user.image ? (
                  <img src={`http://localhost:5001${user.image}`} alt="User" style={{ width: "50px", height: "50px", borderRadius: "50%" }} />
                ) : (
                  <img src="/default-avatar.png" alt="Default Avatar" style={{ width: "50px", height: "50px", borderRadius: "50%" }} />
                )}
              </td>
              <td>{user.name}</td>
              <td>{user.role}</td>
              <td>{user.email}</td>
              <td>
                <button className="edit-btn" onClick={() => handleEdit(user)}>
                  <FaEdit />
                </button>
                <button className="delete-btn" onClick={() => deleteUser(user._id)}>
                  <FaTrash />
                </button>
              </td>
            </tr>
          ))}
        </tbody>
      </table>

      {/* Modal d'édition */}
      {showModal && (
        <div className="modal">
          <div className="modal-content">
            <h2>Edit User</h2>
            <input type="text" name="name" value={formData.name} onChange={handleChange} placeholder="Full Name" />
            <input type="email" name="email" value={formData.email} onChange={handleChange} placeholder="Email" />
            <select name="role" value={formData.role} onChange={handleChange}>
              <option value="client">Client</option>
              <option value="business">Business</option>
              <option value="admin">Admin</option>
            </select>

            <label>Profile Picture:</label>
            <input type="file" accept="image/*" onChange={handleImageChange} />
            {formData.image && <img src={formData.image} alt="Preview" style={{ width: "50px", height: "50px", borderRadius: "50%" }} />}

            <button onClick={handleUpdate}>Update</button>
            <button onClick={() => setShowModal(false)}>Cancel</button>
          </div>
        </div>
      )}
    </div>
  );
};

export default DashboardHome;
